import java.util.*;
public class Main {
    record Product(String name, double price, int stock) {}
    public static void main(String[] args) {
        List<Product> products = new ArrayList<>(List.of(
            new Product("Widget", 9.99, 100),
            new Product("Gadget", 24.99, 50),
            new Product("Doohickey", 4.99, 200)
        ));
        // Sort by price ascending, then by name alphabetically as tiebreaker
        products.sort(Comparator.comparingDouble(Product::price).thenComparing(Product::name));
        products.forEach(System.out::println);
    }
}

