import java.util.*;
public class Main {
    public static void main(String[] args) {
        String[] words = {"the", "quick", "brown", "fox", "the", "quick"};
        // Use HashSet to find unique words and print count
        Set<String> unique = new HashSet<>(Arrays.asList(words));
        System.out.println("Unique words: " + unique.size());
        // Find words present in both arrays using retainAll
        String[] moreWords = {"fox", "jumps", "over", "the"};
        Set<String> common = new HashSet<>(Arrays.asList(words));
        common.retainAll(new HashSet<>(Arrays.asList(moreWords)));
        System.out.println("Common: " + common);
    }
}

